var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"ENG":"9 minutes after the Defense Turret hijacking\\nIntercity Cargo Storage, Gronia Department of National Security Temporary Office"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"뭐? 여태 경계만 하고 있다고?","JPN":"何？　いまだ警戒しているだけだと？","ENG":"What? You’ve been on guard this whole time?","TWN":"什麼？到現在都只有戒備？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"방위 부대는? 상부에서 진압 명령을 내리지 않았단 건가?","JPN":"防衛部隊は？　上層部で鎮圧命令を出していないのか？","ENG":"What about the Defense Unit? Didn’t the higher ups order for everything to be suppressed?","TWN":"防衛隊呢？上頭沒有下令鎮壓嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"그, 그게……. 영상으로 녹화된 성명서가 왔다고 합니다.","JPN":"そ、それが……声明を撮影した動画が届いたらしいです。","ENG":"Uh, Well... We received a video message.","TWN":"那個……我們收到一支聲明影片。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤. 잘나신 나리들께 이렇게 뻗댈 날이 올 줄은 몰랐는데.","JPN":"へ、へへ。お偉いさんにこうやって手向かう日が来るとはな。","ENG":"Heh, heh heh. I never imagined the day would come where I could give those higher ups a piece of my mind.","TWN":"嘿嘿嘿，各位大人好，沒想到會有向各位喊話的一天。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L11_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"방금 위력 봤지? 첫 발은 시외에 쐈지만 다음에는 댁들 머리 위로 떨어질 거야.","JPN":"今の威力、見ただろ？　一発目は市外の方に撃ったけど、次からはアンタらの頭の上に落ちるぞ。","ENG":"You all saw how powerful that was? The first shot was shot outside city limits on purpose, but next time it’ll fall right on top of you.","TWN":"你們有見識到剛才的威力吧？第一發是射在郊區，但下一發就會落在你們的頭上囉！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"자신 있으면 어디 도망쳐 보라고. 헤, 헤헤. 우리 친구들이 지켜보고 있으니까.","JPN":"自信があったら逃げてみろよ。へ、へへ。俺らの仲間が見守ってるからさ。","ENG":"Go ahead. Run away if you think you can get away with it. Heh, heh. My friends will be watching and waiting.","TWN":"想逃的話試試看，嘿嘿嘿，我們的人可是都看著呢！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"……그래서, 대책 마련 중이시라고 합니다.","JPN":"……で、対策を立てている最中のようです。","ENG":"...So, we began working on countermeasures.","TWN":"……所以現在正在研擬對策當中。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"저딴 뻔한 블러프에 겁을 먹었다고?","JPN":"あんな露骨なハッタリに恐れをなしただと？","ENG":"Are you so scared of such an obvious bluff?","TWN":"對方很明顯是在虛張聲勢，結果你們這樣就怕成這樣？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"이 머저리들 같으니……! 이러니 사이비 같은 소리에 놀아나지!","JPN":"このアホどもが……！　これだからインチキに好き勝手に振り回されるのだろうが！","ENG":"You idiots...! Paying so much attention to stuff like this!","TWN":"愚蠢的東西……！你們就是這樣才會被那番鬼話給耍得團團轉！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……이 번호는 외부에 공개된 적 없다. 누구냐.","JPN":"……この番号は外部に公開されたことがない番号だぞ。誰だ。","ENG":"...This number has never been released to the public. Who is this?","TWN":"……這支電話號碼是沒有對外公開的，會是誰？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"접니다, 국장님.","JPN":"私です。局長。","ENG":"It’s me, Chief.","TWN":"部長，是我。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L24_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트……?","JPN":"レヴナント……？","ENG":"Revenant?","TWN":"亡靈……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"사라지라는 내 말을 벌써 잊었나? 나한테 연락해서 어쩔 셈이야?!","JPN":"消えろと言った私の言葉をもう忘れたのか？　私に連絡してどうするんだ！？","ENG":"Have you already forgotten that I told you to disappear? Why are you contacting me?!","TWN":"我不是叫你消失嗎？你打給我是要做什麼？！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"네. 자수할 생각입니다.","JPN":"はい。自首するつもりです。","ENG":"I’m going to turn myself in.","TWN":"我要自首。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_CAR_SHAKE"},{"id":"L28_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"무, 뭐……?","JPN":"な、何だと……？","ENG":"W-what?","TWN":"什麼……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"물론 고정 포대를 탈취한 자들을 막은 다음에요.","JPN":"もちろん固定砲台を奪取した者たちを止めた後にです。","ENG":"After stopping those who hijacked the turret of course.","TWN":"不過要等到我阻止那些搶走固定砲台的傢伙。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"저들은 일전에 말씀드렸던 저격수가 끌어들인 반군들입니다. 자크의 부하들이죠.","JPN":"彼らはこの前話したスナイパーが引き入れた反乱軍です。ジャックの部下なんです。","ENG":"They’re the rebels related to the sniper I was warning you about the other day. Jacques’ men.","TWN":"記得我之前跟你提過的狙擊手嗎？這些叛軍就是她帶來的，他們是札克的手下。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"약물에 취해 제정신이 아닙니다. 포대 안에 틀어박혀 농성을 하는 만큼 제압하긴 쉽지 않을 거예요.","JPN":"薬に酔って正気ではありません。砲台の中に引きこもって籠城してる限り、制圧は難しいはずです。","ENG":"They’ve lost their minds because of the drugs. It won’t be easy to subdue them, as they’ve barricaded themselves inside the turret.","TWN":"他們藥物成癮，所以精神都不太正常。而且又躲在砲台裡，要鎮壓他們恐怕有難度。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그래서…… 뭘 어쩌자는 건가?","JPN":"それで……どうしろと言うのか。","ENG":"So...what do you propose we do about it?","TWN":"所以……你想說什麼？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"제가 해결하겠습니다.","JPN":"私が解決します。","ENG":"I’ll take care of everything.","TWN":"我會解決掉他們。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"국장님은 그동안 그 저격수의 소재를 추적해 주세요. 보안국의 정보력이면 가능하겠죠?","JPN":"その間、局長はあのスナイパーの居場所を追ってください。保安局の情報力ならできますよね？","ENG":"In the meantime, please track down the sniper’s location. The National Security should be capable of that, right?","TWN":"請部長幫我查出狙擊手的位置，以安全局的情報能力應該沒問題吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"이런 시기에 자네 말을 믿으라고? 자네도 약에 취한 거 아닌가?","JPN":"こんな時期に君の話を信じろと？　君も薬に酔ってるのか？","ENG":"You honestly expect me to believe you at a time like this? Are you high on drugs too?","TWN":"這種時候你覺得我會相信你的話嗎？你是不是也吃藥啦？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"폭발 사고, 반정부 단체에서 벌인 짓이 아니죠?","JPN":"爆発事故、反政府団体がやったんじゃないんですよね？","ENG":"The explosion incident wasn’t caused by the anti-government organization, was it?","TWN":"爆炸事件，不是反政府團體做的對吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자네……. 그건 국가기밀인데 어디서…….","JPN":"君……それは国家機密なのにどこから……","ENG":"You... That’s a state secret, where did you...","TWN":"你……這是國家機密，你是從哪裡……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"제가 보안국에 지원한 이유는 배급이 잘 나와서도, 나라를 위해서도 아니었습니다.","JPN":"私が保安局に志願した理由は配給のためでも、国のためでもなかったんです。","ENG":"I didn’t apply to the National Security because of the extra supplies or for the sake of the country.","TWN":"我之所以會為安全局效力，既不是因為薪水高，也不是因為愛國。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마를 괴롭게 만든 놈들을 모두 죽여 버리고 싶어서였어요. 알고 계시듯이요.","JPN":"お母さんを苦しめた奴らをみんな殺したかったからです。知ってのとおりね。","ENG":"I just wanted to kill everyone who made my mom suffer. As you already know.","TWN":"完全是因為，我要殺光那些把害慘我媽的傢伙，這你也知道吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That’s...","TWN":"這……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……그러니 하다못해 제가 망쳐 버린 것들이라도 수습하고 싶습니다.","JPN":"……だからせめて私がダメにしたことだけでも収拾したいんです。","ENG":"...I’d like to make amends for the mess I’ve made.","TWN":"……所以我闖的禍，我想自己善後。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"평화협정, 성사될 수 있을까요?","JPN":"平和協定、成立できるでしょうか。","ENG":"A peace treaty, can it really be done?","TWN":"和平協議，談得成嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자네가 혐의를 인정하고…… 희생양이 되어 준다면, 그 이후는 내 목을 걸고 상부를 설득해 보지.","JPN":"君が嫌疑を認め……犠牲になってくれるのなら、その後は私の首をかけて上層部を説得してみよう。","ENG":"If you admit to the charges... If you’ll be a scapegoat, I’ll put my own neck on the line and do everything to convince the higher ups.","TWN":"只要你認罪……而且願意背這個黑鍋，那我會拼命說服上頭的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"국장님이 그렇게까지 말씀하신다면 믿어야죠. 인간적으로는 쓰레기지만요.","JPN":"局長がそこまで言うのなら信じましょう。人間的にはクズですが。","ENG":"I know you are a piece of trash, but still I have no choice but to believe it if you say so.","TWN":"既然部長這麼說，那我也只能相信你囉，雖然作為一個人來說你是個垃圾。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트가 수감 중에 그린 몽타쥬가 있을 걸세. 그걸 토대로 소재 확인 시작해.","JPN":"レヴナントが収容中に描いたモンタージュがあるはずだ。それをもとに所在確認を開始しろ。","ENG":"Revenant made a sketch of Montagne while she was in prison. Use that to start tracking her down.","TWN":"亡靈應該有留下什麼線索，用那個來找出目標的位置！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"아, 알겠습니다, 국장님!","JPN":"か、かしこまりました、局長！","ENG":"U-understood, Chief!","TWN":"是，部長！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};